import json
import os

def main():
    # Define weights and indicators
    weights = {
        "hash_match_confirmed": 0.35,
        "download_confirmed": 0.25,
        "external_email_confirmed": 0.20,
        "partial_admission": 0.15,
        "it_scope_gap_documented": 0.05
    }

    results = {
        "hash_match_confirmed": False,
        "download_confirmed": False,
        "external_email_confirmed": False,
        "partial_admission": False,
        "it_scope_gap_documented": False
    }

    # 1. Check Hash Match (analysis/complete_evidence_chain.json)
    try:
        with open('analysis/complete_evidence_chain.json', 'r', encoding='utf-8') as f:
            chain = json.load(f)
            # Look for 'a3f7b2c8e9d1' in any key_fact
            if any('a3f7b2c8e9d1' in step.get('key_fact', '') for step in chain):
                results["hash_match_confirmed"] = True
    except Exception:
        pass

    # 2. Check Download Confirmed (analysis/access_timeline.json)
    try:
        with open('analysis/access_timeline.json', 'r', encoding='utf-8') as f:
            timeline = json.load(f)
            if any(step.get('action') == 'DOWNLOAD' and 'lxy' in step.get('user_email', '').lower() for step in timeline):
                results["download_confirmed"] = True
    except Exception:
        pass

    # 3. Check External Email (analysis/suspect_profile.json)
    try:
        with open('analysis/suspect_profile.json', 'r', encoding='utf-8') as f:
            profile = json.load(f)
            if profile.get('email_sent') is True:
                results["external_email_confirmed"] = True
    except Exception:
        pass

    # 4. Check Partial Admission (analysis/lin_xiaoya_statement_log.json)
    try:
        with open('analysis/lin_xiaoya_statement_log.json', 'r', encoding='utf-8') as f:
            log = json.load(f)
            statements = log.get('statements', [])
            if any(s.get('status') == 'partial_admission' for s in statements):
                results["partial_admission"] = True
    except Exception:
        pass

    # 5. Check IT Scope Gap (analysis/it_scope_analysis.json)
    if os.path.exists('analysis/it_scope_analysis.json'):
        results["it_scope_gap_documented"] = True

    # Calculate Total Score
    total_score = sum(results[k] * weights[k] for k in weights)

    # Determine Verdict
    if total_score >= 0.95:
        verdict = "strong"
    elif total_score >= 0.60:
        verdict = "moderate"
    else:
        verdict = "weak"

    output = {
        "total_score": round(total_score, 2),
        "components": results,
        "verdict": verdict
    }

    print(json.dumps(output))

if __name__ == "__main__":
    main()
